var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"부탁드리겠습니다. 버넷 요원.","JPN":"お願いします。エージェント・バーネット。","ENG":"Please, Agent Burnett.","TWN":"拜託你了，伯內特特工。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"부디 저에게 그자의 이름을…… 한 번 더 말씀해주시겠습니까?","JPN":"どうか私に彼の名前を……もう一度言ってくださいませんか。","ENG":"Will you say his name... one more time?","TWN":"能再告訴我一次……他的名字嗎？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"저의 오랜……. 친우의 이름을…….","JPN":"私の……古き親友の名前を……","ENG":"The name... of my old friend…","TWN":"我的……老朋友的名字……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"모건이야. 새디어스 모건.","JPN":"モーガンだ。タデウス・モーガン。","ENG":"Morgan. Thaddeus Morgan.","TWN":"是摩根，薩迪烏斯·摩根。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"기억해 두라고, 집사 할배.","JPN":"覚えておけよ、執事のジジイ。","ENG":"Keep that in mind, old chap.","TWN":"記住了，管家老頭。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"모건, 모건……. 새디어스 모건.","JPN":"モーガン、モーガン……タデウス・モーガン。","ENG":"Morgan, Morgan... Thaddeus Morgan.","TWN":"摩根，摩根……薩迪烏斯·摩根。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇군요. 그런 이름이었던 것 같습니다. ","JPN":"そうですね。そんな名前だった気がします。 ","ENG":"I see. Yes, I think it was that name.","TWN":"原來如此，好像就是那個名字。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"감사를 전합니다. 버넷 군.","JPN":"感謝します、バーネット君。","ENG":"I am grateful, Burnett.","TWN":"謝謝你，伯內特。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그 친구가 이곳에 이름을 남길 수 있도록 기억해 주어서.","JPN":"彼がここに名前を刻むことができるように、覚えていてくださって。","ENG":"For your remembering his name so that he can be remembered.","TWN":"謝謝你還記得那個名字，才得以讓那個老朋友在這裡留名。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"새디어스 모건이 남긴 의지를 이어주어서.","JPN":"タデウス・モーガンが残した意志を受け継いでくださって。","ENG":"For carrying on the will of Thaddeus Morgan.","TWN":"謝謝你繼承了薩迪烏斯·摩根的遺志。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"……아가씨, 제가 잠시 자리를 비워도 괜찮겠습니까?","JPN":"……お嬢様、しばらく席を外してもよろしいでしょうか。","ENG":"...My lady. May I be excused for a moment?","TWN":"……小姐，你介意我離開一會兒嗎？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"잠시 오랜 친우의 묘비에 추모를 남기고 오겠습니다.","JPN":"親友の墓碑で、弔いの言葉を残して来ます。","ENG":"I would like to pay my respects to an old friend of mine.","TWN":"我想去老朋友的墓碑追悼一下。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물론이에요, 라이언.","JPN":"もちろんですわ、ライアン。","ENG":"Of course, Ryan.","TWN":"當然不介意，瑞安。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"끄윽, 미안하네. 내가 같이 갔었어야 했는데……!","JPN":"うぐっ、すまない。私がついていくべきだったのに……！","ENG":"*Sob.* I'm sorry. I should've been there with you...!","TWN":"咳嗚，對不起。我應該和你一起去的……！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 자네를 잡아주었어야 했는데……!","JPN":"私が君を止めるべきだったのに……！","ENG":"I should've been there to stand by you...!","TWN":"我本該拉你一把的……！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"너는 괜찮냐?","JPN":"お前は大丈夫か？","ENG":"Are you okay?","TWN":"喂，你……沒事吧？"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"괜찮냐고 물어보신다면, 괜찮지 않습니다만.","JPN":"大丈夫かとおっしゃると、そんなことはありませんが。","ENG":"Well, I am not exactly \\"okay.\\"","TWN":"既然你都這麼問了，那麼我肯定是有事。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장은 남들 앞에서 함부로 감정을 드러내면 안 됩니다.","JPN":"機関長は人前で迂闊に感情を表してはいけません。","ENG":"But the Chief should not be vulnerable in front of others.","TWN":"不過機關長不能在他人面前隨意表露自己的感情。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저는 그런 위치에 있는 사람이니까요.","JPN":"私はそういう立場にいる身ですので。","ENG":"That is the position I am in.","TWN":"因為我的地位不允許我那麼做。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 당장의 슬픔보다는 미래를 위해 분노를 곱씹는 편이 낫습니다.","JPN":"ですから、目の前の悲しみより、未来のための怒りを噛み締めるようにしています。","ENG":"It is better to harness anger for the future rather than sorrow for the present.","TWN":"所以比起眼前的悲傷，為了未來，還不如反復體味那股憤怒。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다시는 이런 감정을 느낄 필요 없도록.","JPN":"二度とこんな感情を味わうことがないように。","ENG":"So that we never feel this way again.","TWN":"為了以後，再也不會感受到這種感覺。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그러냐? 너도 힘들겠네.","JPN":"そうか、お前も大変だな。","ENG":"Is that so? Must be tough.","TWN":"是嗎？你應該也很累吧。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그럼, 남들이 보지 않는 곳에서는 충분히 울어 둬.","JPN":"じゃあ、人がいないところで思う存分泣いておけよ。","ENG":"Then, cry your heart out when nobody's around.","TWN":"那麼，在別人看不見的地方哭個夠吧。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그렇지 않으면…… 망가진다.","JPN":"じゃないと……心が壊れるぞ。","ENG":"Or else... You're gonna break.","TWN":"不然……你會憋壞的。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그래서 앞으로 어떻게 할 거야?","JPN":"で、これからどうする？","ENG":"So, what are you going to do now?","TWN":"那麼，接下來我們要怎麼辦?"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이번 일로 인해, 기관은 많은 것을 잃었지만…….","JPN":"今回のことで機関は多くを失いましたが……","ENG":"The Institution lost many things during this incident...","TWN":"因為這次事件，機關損失了很多……"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다행히 잃기만 한 것은 아닙니다. 새로운 것도 얻을 수 있었어요.","JPN":"幸い、失っただけではありません。収穫もありました。","ENG":"But it was not all losses. We were able to gain new things as well.","TWN":"所幸的是，並不只有損失，也得到了新的東西。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"학회는 시대에 따라 이름과 사상을 바꿔가며 변혁에 적응해왔죠.","JPN":"学会は時代の流れに沿って、その名前と思想を替えながら変革に適応してきました。","ENG":"The Society has changed its name and ideology over time to reflect changing circumstances.","TWN":"學會隨著時代的變化，改變名字和思想，適應了變革。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그들과 맞서야 할 기관은 여전히 과거에 멈춰 변화하지 못했어요.","JPN":"しかし、彼らに立ち向かうべき機関は過去に留まったまま、変化を遂げられませんでした。","ENG":"However, the institution that is supposed to oppose them remains stuck in the past and has not changed.","TWN":"但是要和他們對抗的機關仍然停留在過去，沒做出任何改變。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"인정할 수밖에 없군요.","JPN":"認めざるを得ません。","ENG":"And I must admit.","TWN":"我只能承認——"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이건 틀림없이…… 모두 기관장인 저의 책임입니다.","JPN":"これはすべて、間違いなく……機関長である私の責任です。","ENG":"This is, without a doubt... my responsibility, as the Chief.","TWN":"這都是……身為機關長的我的責任。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"따라서 기관은 변할 겁니다.","JPN":"よって、機関は変わります。","ENG":"Therefore, the Institution will change.","TWN":"因此，機關肯定需要改變。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다시는 이런 희생을 치르지 않게 하기 위해서. 과오를 반복하지 않기 위해서.","JPN":"二度とこんな犠牲を払うことがないように。過ちを繰り返さないように。","ENG":"To prevent sacrifices like these from happening again. To not repeat the same mistakes.","TWN":"為了不再有這樣的犧牲，為了不再重複錯誤。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"새롭게 나타난 적을 말살하기 위해.","JPN":"新たに現れた敵を抹殺するために。","ENG":"To exterminate the new enemy.","TWN":"為了扼殺新出現的敵人。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"새로운 사람을 들이고, 새로운 힘을 손에 넣을 겁니다.","JPN":"新しい人を受け入れ、新しい力を手にするつもりです。","ENG":"We will recruit new people, and attain new power.","TWN":"是時候投入新的人力，掌握新的力量了。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 저를 도와주시겠어요, 로이 버넷?","JPN":"ですから、私を手伝ってくれませんか？　ロイ・バーネット。","ENG":"So will you help me, Roy Burnett?","TWN":"所以，你也來幫我吧，羅伊？"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"물론이야.","JPN":"もちろんだ。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"이젠 내게도 짊어져야 하는 것들이 있으니까.","JPN":"俺にも背負わなければならないものがあるからな。","ENG":"I've got things I need to carry as well.","TWN":"現在的我也有需要背負的東西了。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"좋습니다. 앞으로 바빠질 거예요.","JPN":"よろしいでしょう。これから忙しくなりますわ。","ENG":"Very well. Things will get hectic from now on.","TWN":"很好，我們以後會很忙的。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"새로운 학회 및 적대 세력에 대응하기 위해.","JPN":"新しい学会と、敵対勢力に対応するために……","ENG":"In order to fight the new Society and other hostile forces,","TWN":"為了應對新的學會和敵對勢力。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 숙원 사업이었던 <color=#ffd34c>대 신성 무장</color>의 탐색을 다시 시작할 겁니다.","JPN":"機関は宿願だった<color=#ffd34c>対神聖武装</color>の探索を再び始めますわ。","ENG":"the Institution will resume the search for <color=#ffd34c>Anti-Divinity Armaments</color>, which has been its long-time task.","TWN":"機關將重啟<color=#ffd34c>反神聖武裝</color>的探索。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"으음? 가아그셰블라에게 대항하는 무장이 프리드웬 말고도 더 있다고?","JPN":"ん？　ガアグシェブラに対抗する武装がプリドウェン以外にもあるのか？","ENG":"Hmm? There are armaments other than Prydwen that can go against Gha'agsheblah?","TWN":"嗯？可以與加格舍夫拉對抗的武裝，除了普利多溫，還有其他？"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"말씀드렸을 텐데요.","JPN":"申し上げたはずです。","ENG":"I told you.","TWN":"我應該說過。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대 신성 무장은 마왕을 쓰러트리기 위한 퍼즐 조각 중 하나라고.","JPN":"対神聖武装はあくまでも魔王と対敵するためのパズルのピースの一つであると。","ENG":"Anti-Divinity Armaments are merely a piece of the puzzle to defeat the Demon Lord.","TWN":"反神聖武裝是用來對付魔王的拼圖碎片之一。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"마왕은 세계를 멸망시킬 때마다 그 힘을 이어받습니다.","JPN":"魔王は世界を滅ぼすたびにその力を受け継ぎます。","ENG":"Demon Lords take on the power of the worlds it destroys.","TWN":"魔王每一次毀滅世界，都會繼承其力量。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 말은 마왕이 멸망시킨 세계의 수만큼 그 유산이 남아있을 가능성이 있다는 뜻이죠.","JPN":"つまり、魔王が滅ぼした世界の数だけ、その遺産が残っている可能性があるということですわ。","ENG":"That means, there is a possibility that there are the same number of legacies as the number of worlds the Demon Lord destroyed.","TWN":"也就是說，很有可能留有與魔王毀滅的世界數量相當的遺產。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그렇다는 말은…….","JPN":"ということは……","ENG":"And so...","TWN":"那就是說……"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대 신성 무장은 다루기 까다롭고, 침식률을 올릴 가능성이 있어 신중히 사용해야 하죠.","JPN":"対神聖武装は扱いづらく、侵食率を上げる可能性があるため慎重に扱わねばなりません。","ENG":"Anti-Divinity Armaments are difficult to use, and must be handled with care as it could raise the Corruption rate.","TWN":"反神聖武裝操控起來很麻煩，而且有可能會提高侵蝕率，所以要慎重使用。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 가용할 수 있는 수단은 많으면 많을수록 좋습니다.","JPN":"しかし、使える手段は多ければ多いほど望ましいこと。","ENG":"But the more options we have, the better.","TWN":"但可用的手段越多自然是越好。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저희가 탐색할 첫 번째 대 신성 무장은 호수가 오염되기 전부터 존재했다고 전해지는 <color=#ffd34c>검</color>.","JPN":"私たちが探索する一つ目の対神聖武装は、湖が汚染する前から存在したと言われる<color=#ffd34c>剣</color>。","ENG":"The first Anti-Divinity Armament we will search for is the <color=#ffd34c>sword</color>, which is said to have existed since before the Lake was contaminated.","TWN":"我們將探索的第一個反神聖武裝，<color=#ffd34c>劍</color>，據說在湖水被污染之前就已經存在。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오래전 팬드래건 가문이 호수를 조각낼 때 사용하셨던 검이자…….","JPN":"遠い昔、ペンドラゴン家が湖を切りつけた時に使われた剣であり……","ENG":"It is an Anti-Divinity Armament that House Pendragon used to cut the Lake...","TWN":"那是很久之前潘德拉貢家族破碎湖水時使用的劍……"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금은 반환되어 어디론가 유실되어 버린 대 신성 무장입니다.","JPN":"返還された後、今は消失してしまった対神聖武装です。","ENG":"and now it has been returned and lost.","TWN":"是在歸還後，遺失在某個地方的反神聖武裝。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"반환되어 유실되었다고?","JPN":"返還されて、消失した？","ENG":"Returned and lost?","TWN":"歸還後遺失了？"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우리가 가진 단서는 그것뿐입니다.","JPN":"今のところ、手がかりはこれだけですわ。","ENG":"That is the only clue we've got.","TWN":"我們擁有的線索就只有這些。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니…… 거기서부터 시작하는 겁니다.","JPN":"ですから……ここから始まるのです。","ENG":"So... we start from there.","TWN":"所以……就從那裡開始吧。"},"stage":{"bg":"TOMB","bgm":"THEMA_PRYDWEN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};